public static real getMonthlyPurchaseQty(
ETGItemNumber    _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)

{
    real purchaseQty = 0;

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    Set summedTrans = new Set(Types::Int64);

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Purch
    {
        // Check if at least one valid InventTransPosting exists
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            purchaseQty += inventTrans.Qty;
            summedTrans.add(inventTrans.RecId);
        }
    }

    return purchaseQty;
}

// Sales qty
public static real getMonthlySalesQty(
ETGitemnumber    _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real salesQty = 0;
    Set summedTrans = new Set(Types::Int64);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Sales
    {
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            salesQty += inventTrans.Qty;
            summedTrans.add(inventTrans.RecId);
        }
    }

    return salesQty;
}

public static real getMonthlySalesValue(
ETGitemnumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real salesValue = 0;
    Set seenInvoiceTrans = new Set(Types::Int64); // Track CustInvoiceTrans.RecId

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;
    CustInvoiceTrans custInvoiceTrans;

    while select inventTrans
    where inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && inventTrans.DateFinancial != dateNull()
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Sales
join inventTransPosting
    where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
       && inventTransPosting.ItemId == _item
       && inventTransPosting.IsPosted == NoYes::Yes
       && inventTransPosting.ETGCommodity == _comm
       && inventTransPosting.ETGSubCommodity == _subComm
       && inventTransPosting.ETGVertical == _ver
       && inventTransPosting.ETGSubVertical == _subVer
    {
        // Match invoice line using InventTransId only
        // Restricting join by InvoiceDate to handle edge cases
        // where a single InventTransId is associated with multiple invoice lines.
        while select custInvoiceTrans
        where custInvoiceTrans.InventTransId == inventTransOrigin.InventTransId
         //  && custInvoiceTrans.InvoiceId == inventTrans.InvoiceId
           && custInvoiceTrans.InvoiceDate == inventTrans.DateFinancial
        {
            if (!seenInvoiceTrans.in(custInvoiceTrans.RecId))
            {
                salesValue += custInvoiceTrans.LineAmountMST;
                seenInvoiceTrans.add(custInvoiceTrans.RecId);
            }
        }
    }

    return salesValue;
}

public static real getSalesOrderQtyGroup(
ETGitemnumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real salesQty = 0;
    Set summedTrans = new Set(Types::Int64);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;
    SalesTable salesTable;
    CustTable custTable;

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Sales
    {
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            salesTable = SalesTable::find(inventTransOrigin.ReferenceId);
            if (salesTable)
            {
                custTable = CustTable::find(salesTable.CustAccount);
                if (custTable.CustGroup == '40')
                {
                    salesQty += inventTrans.Qty;
                    summedTrans.add(inventTrans.RecId);
                }
            }
        }
    }

    return salesQty;
}

