public static real getSalesOrderQtyGroup3rdParty(
ETGitemnumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real salesQty = 0;
    Set summedTrans = new Set(Types::Int64);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;
    SalesTable salesTable;
    CustTable custTable;

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Sales
    {
        // Check only the first valid posting record to avoid duplication
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical ==_subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            salesTable = SalesTable::find(inventTransOrigin.ReferenceId);
            if (salesTable)
            {
                custTable = CustTable::find(salesTable.CustAccount);
                if (custTable.CustGroup != '40')
                {
                    salesQty += inventTrans.Qty;
                    summedTrans.add(inventTrans.RecId);
                }
            }
        }
    }

    return salesQty;
}

public static real getMonthlyPurchaseValue(
ETGItemNumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real purchaseValue = 0;

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    Set summedTrans = new Set(Types::Int64);

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Purch
    {
        // Only proceed if there is at least one matching InventTransPosting
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            purchaseValue += inventTrans.CostAmountPosted + inventTrans.CostAmountAdjustment;
            summedTrans.add(inventTrans.RecId);
        }
    }

    return purchaseValue;
}

//Transfer qty
public static real getStockTransferQtyCumulativeByMonth(
ETGItemNumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _fiscalStartDate,
date             _monthEndDate)
{
    real transferQty = 0;

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    Set summedTrans = new Set(Types::Int64); // To avoid duplicate counting

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _fiscalStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
      && (inventTransOrigin.ReferenceCategory == InventTransType::TransferOrderShip
          || inventTransOrigin.ReferenceCategory == InventTransType::TransferOrderReceive)
    {
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGVertical == _ver
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            transferQty += inventTrans.Qty;
            summedTrans.add(inventTrans.RecId);
        }
    }

    return transferQty;
}

