public void insertReportData()
{
    ETGGCReportStaging staging, StagingPrev;
    DataArea dataArea;
    int i = 1;

    aCFParameters = ETGACFParameters::find(true);
    select * from dataArea where dataArea.Id == curExt();

    TransDate lastExportedDate = aCFParameters.GCReportLastExportedDate;
    if (lastExportedDate)
    {
        select RecordNum from StagingPrev order by  RecordNum desc;
        i = any2Int(StagingPrev.RecordNum) +1;

    }
    TransDate currentExportDate = today();
    if (!lastExportedDate || lastExportedDate == dateNull())
    {
        lastExportedDate = mkDate(01,12,2022);
    }


    TransDate minDate = DateStartMth(lastExportedDate);
    TransDate maxDate1 = endMth(currentExportDate);

    GeneralJournalAccountEntry gjAccEntry;
    GeneralJournalEntry gjEntry;

    DimensionDefault dimDefault;
    Map fdCombinationMap = new Map(Types::String, Types::Container);
    Set processedKeySet = new Set(Types::String);
    RecordInsertList ril = new RecordInsertList(tablenum(ETGGCReportStaging));

    this.getFiscalYearDate(currentExportDate);

    // Preload dimension combinations
    while select firstonly10 gjAccEntry
    join gjEntry
    where gjAccEntry.GeneralJournalEntry == gjEntry.RecId
        && gjEntry.SubledgerVoucherDataAreaId == curExt()
       // && gjEntry.SubledgerVoucher =='O001VI_26003382'
    {
        dimDefault = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(gjAccEntry.LedgerDimension);
        Map dimMap = ETGPrepareDataForGCReportService::getDimensionMap(dimDefault, aCFParameters);



        str etgItemid = dimMap.lookup("ItemId");
        //if(etgItemid != "01072502750000750600")
        //{
        //    continue;
        //}
        str etgCommodity = dimMap.lookup("MainCommodity");
        str etgSubCommodity = dimMap.lookup("SubCommodity");
        str etgVertical = dimMap.lookup("Vertical");
        str etgSubVertical = dimMap.lookup("SubVertical");

        str dimKey = strFmt('%1|%2|%3|%4|%5', etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical); //todo add item id
        if (!fdCombinationMap.exists(dimKey))
        {
            fdCombinationMap.insert(dimKey, [etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical]); //todo add item id
        }

    }

    // Process each dimension set
    MapEnumerator mapEnum = fdCombinationMap.getEnumerator();
    while (mapEnum.moveNext())
    {
        container dimParts = mapEnum.currentValue();

        str etgItemid = conPeek(dimParts, 1);
        str etgCommodity = conPeek(dimParts, 2);
        str etgSubCommodity = conPeek(dimParts, 3);
        str etgVertical = conPeek(dimParts, 4);
        str etgSubVertical = conPeek(dimParts, 5);


        TransDate currentMonth = minDate;
        while (currentMonth <= currentExportDate)
        {
            int year = year(currentMonth);
            int month = mthOfYr(currentMonth);
            str dedupKey = strFmt('%1|%2|%3|%4|%5|%6|%7',etgItemid, etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, year, month);

            if (!processedKeySet.in(dedupKey))
            {
                processedKeySet.add(dedupKey);

                staging.clear();
                staging.TransDate = currentMonth;
                staging.Year = year;
                staging.MonthName = mthName(month);
                staging.Isinvent = NoYes::Yes;
                staging.ItemId  = etgItemid;
                staging.ItemName = InventTable::find(etgitemid).productNameInSystemLanguage();
                staging.ETGCommodity = etgCommodity;
                staging.ETGSubCommodity = etgSubCommodity;
                staging.ETGVertical = etgVertical;
                staging.ETGSubVertical = etgSubVertical;

                TransDate fiscalYrStartDate = fiscalYearStartDate;//mkDate(01,04, 2025);

                staging.OpeningQty = ETGPrepareDataForGCReportService::calculateMonthlyCumulativeStockQty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fiscalYrStartDate);
                staging.OpeningstockOPeningLC = ETGPrepareDataForGCReportService::calculateMonthlyCumulativeStockOpeningValue(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fiscalYrStartDate);
                staging.ClosingQty = ETGPrepareDataForGCReportService::calculateMonthlyCumulativeStockClosingQty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, currentMonth);
                staging.ClosingStockvalue = ETGPrepareDataForGCReportService::calculateMonthlyCumulativeStockClosingValue(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, currentMonth);

                TransDate fromDate = fiscalYearStartDate;//mkDate(01,04, 2025);//DateStartMth(currentMonth);
                TransDate toDate = endMth(currentMonth);

                staging.StockTransferQty = ETGPrepareDataForGCReportService::getStockTransferQtyCumulativeByMonth(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.StockTransferValueLC = ETGPrepareDataForGCReportService::getStockTransferValueCumulativeByMonth(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);

                staging.SalesQty = -ETGPrepareDataForGCReportService::getMonthlySalesQty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.SalesValueinLC = ETGPrepareDataForGCReportService::getMonthlySalesValue(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.SalesQty3rdParty = -ETGPrepareDataForGCReportService::getSalesOrderQtyGroup3rdParty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.SalesValue3rdParty = ETGPrepareDataForGCReportService::getSalesOrderValueThirdParty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.SalesQtyGroup = -ETGPrepareDataForGCReportService::getSalesOrderQtyGroup(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.SalesValueGroup = ETGPrepareDataForGCReportService::getSalesOrderValueGroup(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);

                staging.PurchQty = ETGPrepareDataForGCReportService::getMonthlyPurchaseQty(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);
                staging.PurchValueLC = ETGPrepareDataForGCReportService::getMonthlyPurchaseValue(etgItemid,etgCommodity, etgSubCommodity, etgVertical, etgSubVertical, fromDate, toDate);

                staging.RecordNum = int2Str(i);
                staging.LocalCurrency = Ledger::accountingCurrency();
                staging.EntityName = dataArea.Name;
                staging.ExchInUSD   = this.getExchangeRate();
                i++;

                ril.add(staging);
            }
            currentMonth = nextMth(currentMonth);
        }
    }

    // Commit inventory records
    ril.insertDatabase();

    // Cache Power BI Mapping
    mappingCache = new Map(Types::String, Types::String);
    ETGPowerBIReportGLMappingTable mapping;
    while select mapping where mapping.ReportId == "GC Report"
    {
        mappingCache.insert(mapping.MainAccountId,mapping.REPORTPERTICULARID);
    }

    // Non-inventory incremental export
    GeneralJournalAccountEntry generalJournalAccountEntry;
    GeneralJournalEntry generalJournalEntry;
    AgreementLine aLine;
    ril = new RecordInsertList(tablenum(ETGGCReportStaging));

    while select  generalJournalAccountEntry
    join generalJournalEntry
    where generalJournalAccountEntry.GeneralJournalEntry == generalJournalEntry.RecId
        && generalJournalEntry.SubledgerVoucherDataAreaId == curExt()
        && generalJournalEntry.AccountingDate > lastExportedDate
       // && generalJournalEntry.SubledgerVoucher == 'O001VI_26003382'
    {
        DimensionDefault dimDefault1 = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(generalJournalAccountEntry.LedgerDimension);
        TransDate transDate = generalJournalEntry.AccountingDate;
        int year = year(transDate);
        int month = mthOfYr(transDate);

        Map dimMap = ETGPrepareDataForGCReportService::getDimensionMap(dimDefault1, aCFParameters);

        str etgitemid = dimMap.lookup("ItemId");
        str etgCommodity = dimMap.lookup("MainCommodity");
        str etgSubCommodity = dimMap.lookup("SubCommodity");
        str etgVertical = dimMap.lookup("Vertical");
        str etgSubVertical = dimMap.lookup("SubVertical");

        staging.clear();
        staging.LedgerDimension = generalJournalAccountEntry.LedgerDimension;
        staging.SubledgerVoucher = generalJournalEntry.SubledgerVoucher;
        staging.TransDate = transDate;
        staging.Year = year;
        staging.MonthName = mthName(month);
        staging.LocalCurrency = Ledger::accountingCurrency();
        staging.EntityName = dataArea.Name;
        staging.Isinvent = NoYes::No;
        staging.RecordNum = int2Str(i);
        i++;
        staging.Contract  = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(dimDefault1,aCFParameters.Contract);

        //if((etgitemid && etgitemid != "01072502750000750600") || staging.Contract == "")
        //{
        //    continue;
        //}

        if(etgitemid == "")
        {
            RefRecId  agreementHeaderRecId = PurchAgreementHeader::findAgreementId(staging.Contract).RecId;
            if(!agreementHeaderRecId)
            {
                agreementHeaderRecId = SalesAgreementHeader::findAgreementId(staging.Contract).RecId;
            }
            if(agreementHeaderRecId)
            {
                select firstonly ItemId from aLine where aLine.Agreement == agreementHeaderRecId;
                etgitemid = aLine.ItemId;
            }
        }


        staging.ItemId   = etgitemid;
        staging.ItemName = InventTable::find(etgitemid).productNameInSystemLanguage();
        staging.ETGCommodity = etgCommodity;
        staging.ETGSubCommodity = etgSubCommodity;
        staging.ETGVertical = etgVertical;
        staging.ETGSubVertical = etgSubVertical;


        MainAccount sourceMainAccount = MainAccount::find(generalJournalAccountEntry.MainAccount);
        if (mappingCache.exists(sourceMainAccount.MainAccountId))
        {
            Name mainAccountName = mappingCache.lookup(sourceMainAccount.MainAccountId);
            // Name mainAccountName = MainAccount::findByMainAccountId(mappingCache.lookup(sourceMainAccount.MainAccountId)).Name;
            this.assignChargesFromMainAccount(staging,mainAccountName, generalJournalAccountEntry.AccountingCurrencyAmount);
        }

        staging.ExchInUSD = this.getExchangeRate();
        ril.add(staging);
    }

    ril.insertDatabase();

    // Update export timestamp
    ttsbegin;
    aCFParameters.GCReportLastExportedDate = currentExportDate;
    aCFParameters.update();
    ttscommit;
}

