            }
            finally
            {
               currentMonth = nextMth(currentMonth);
            }
        }
    }

    try
    {
        ril.insertDatabase();
        info("GL data inserted.");
    }
    catch(Exception::Error)
    {
        error("error encountered durng GL insertion");
    }
    finally
    {
    }
    // Update export timestamp
    ttsbegin;
    aCFParameters.GCReportLastExportedDate = currentExportDate;
    aCFParameters.update();
    ttscommit;
}

public static Qty getPurchaseQtyByLedgerDimension(
ETGItemNumber    _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer)
{
    Qty totalQty = 0;
    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    while select inventTrans
        where inventTrans.DateFinancial != dateNull()
    join inventTransOrigin
        where inventTrans.InventTransOrigin == inventTransOrigin.RecId
          && inventTransOrigin.ReferenceCategory == InventTransType::Purch
    join inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.ItemId == _item
          && inventTransPosting.ETGCommodity == _comm
          && inventTransPosting.ETGSubCommodity == _subComm
          && inventTransPosting.ETGSubVertical == _subVer
          && inventTransPosting.ETGVertical == _ver
    {
        totalQty += inventTrans.Qty;
    }

    return totalQty;
}

public void getFiscalYearDate(TransDate _date)
{
    RecId calendarRecId;
    //Date transDate = today();
    FiscalCalendarYear fiscalCalenderYear;

    calendarRecId      = Ledger::fiscalCalendar(CompanyInfo::find().RecId);
    fiscalCalenderYear =  FiscalCalendarYear::findYearByCalendarDate(calendarRecId, _date);

    if (fiscalCalenderYear)
    {
        fiscalYearStartDate = fiscalCalenderYear.StartDate;
    }
    else
    {
        throw error("No fiscal period found for the given date.");
    }
}

// to get opening Balance
public static real calculateMonthlyCumulativeStockQty(
 str _etgitemid,
str _etgCommodity,
str _etgSubCommodity,
str _etgVertical,
str _etgSubVertical,
TransDate _monthStartDate)
{
    real totalQty = 0.0;
    TransDate strdate = DateStartMth(_monthStartDate);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;

    Set summedTrans = new Set(Types::Int64); // Avoid double-counting

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial < strdate
       && !summedTrans.in(inventTrans.RecId)
join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
    {
        select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
          && inventTransPosting.IsPosted == NoYes::Yes
          && inventTransPosting.ItemId == _etgitemid
          && inventTransPosting.ETGCommodity == _etgCommodity
          && inventTransPosting.ETGSubCommodity == _etgSubCommodity
          && inventTransPosting.ETGVertical == _etgVertical
          && inventTransPosting.ETGSubVertical == _etgSubVertical;

        if (inventTransPosting.RecId)
        {
            totalQty += inventTrans.Qty;
            summedTrans.add(inventTrans.RecId);
        }
    }

    return totalQty;
}

public void glAmountYTD(
 str _etgitemid,
str _etgCommodity,
str _etgSubCommodity,
str _etgVertical,
str _etgSubVertical,
ETGGCReportStaging staging,
TransDate _monthStartDate)
{
    real totalAmount = 0.0;
    // TransDate strdate = DateStartMth(_monthStartDate);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;
    GeneralJournalEntry GJE;
    GeneralJournalAccountEntry GJAEMain;
    ETGGeneralJOurnalAccountEntryMMR GJAEMMR;

    Set summedTrans = new Set(Types::Int64);

    while select AccountingCurrencyAmount, RecId, MainAccount, LedgerDimension from GJAEMain
        join AccountingDate from GJE
        where GJE.RecId == GJAEMain.GeneralJournalEntry
        && GJE.AccountingDate != dateNull()
        && GJE.AccountingDate <= _monthStartDate
        exists join GJAEMMR
        where GJAEMMR.GeneralJournalAccountEntryRecId == GJAEMain.RecId
         && GJAEMMR.ItemId == _etgitemid
          && GJAEMMR.Commodity == _etgCommodity
          && GJAEMMR.SubCommodity == _etgSubCommodity
          && GJAEMMR.Vertical == _etgVertical
          && GJAEMMR.SubVertical == _etgSubVertical
    {
        if (GJAEMain.RecId)
        {

            RecId dimDefault1 = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(GJAEMain.LedgerDimension);
           // staging.Contract  = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(dimDefault1, aCFParameters.Contract);

            MainAccount sourceMainAccount = MainAccount::find(GJAEMain.MainAccount);

            //  this.assignChargesFromMainAccount(staging, mainAccountName, totalAmount);
            if (mappingCache.exists(sourceMainAccount.MainAccountId))
            {
                Name        mainAccountName   = mappingCache.lookup(sourceMainAccount.MainAccountId);//sourceMainAccount.Name;
                this.assignChargesFromMainAccount(staging, mainAccountName, GJAEMain.AccountingCurrencyAmount);
            }
        }
    }
}

    // opening value
    public static real calculateMonthlyCumulativeStockOpeningValue(
    str _etgitemid,
    str _etgCommodity,
    str _etgSubCommodity,
    str _etgVertical,
    str _etgSubVertical,
    TransDate _monthEndDate // Month end input, but we use start of month for opening
)
    {
        real totalValue = 0.0;
        TransDate startOfMonth = DateStartMth(_monthEndDate); // Opening value: transactions before this

        InventTrans inventTrans;
        InventTransOrigin inventTransOrigin;
        InventTransPosting inventTransPosting;

        Set summedTrans = new Set(Types::Int64); // Avoid double-counting

        while select inventTrans
        where inventTrans.DateFinancial != dateNull()
            && inventTrans.DateFinancial < startOfMonth // Key difference!
            && !summedTrans.in(inventTrans.RecId)
    join inventTransOrigin
        where inventTransOrigin.RecId == inventTrans.InventTransOrigin
        {
            select firstOnly RecId
        from inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
            && inventTransPosting.IsPosted == NoYes::Yes
            && inventTransPosting.ItemId == _etgitemid
            && inventTransPosting.ETGCommodity == _etgCommodity
            && inventTransPosting.ETGSubCommodity == _etgSubCommodity
            && inventTransPosting.ETGVertical == _etgVertical
            && inventTransPosting.ETGSubVertical == _etgSubVertical;

            if (inventTransPosting.RecId)
            {
                totalValue += inventTrans.CostAmountPosted + inventTrans.CostAmountAdjustment;
                summedTrans.add(inventTrans.RecId);
            }
        }

        return totalValue;
    }

public static real getSalesOrderValueGroup(
ETGitemnumber     _item,
ETGCommodity     _comm,
ETGSubCommodity  _subComm,
ETGVertical      _ver,
ETGSubVertical   _subVer,
date             _monthStartDate,
date             _monthEndDate)
{
    real salesValue = 0;
    Set summedTrans = new Set(Types::Int64);

    InventTrans inventTrans;
    InventTransOrigin inventTransOrigin;
    InventTransPosting inventTransPosting;
    SalesTable salesTable;
    CustTable custTable;
    CustInvoiceTrans custInvoiceTrans;

    while select inventTrans
    where inventTrans.DateFinancial != dateNull()
       && inventTrans.DateFinancial >= _monthStartDate
       && inventTrans.DateFinancial <= _monthEndDate
       && !summedTrans.in(inventTrans.RecId)
    join inventTransOrigin
    where inventTransOrigin.RecId == inventTrans.InventTransOrigin
       && inventTransOrigin.ReferenceCategory == InventTransType::Sales
    {
        select firstOnly inventTransPosting
        where inventTransPosting.InventTransOrigin == inventTransOrigin.RecId
           && inventTransPosting.ItemId == _item
           && inventTransPosting.ETGSubCommodity == _subComm
           && inventTransPosting.ETGCommodity == _comm
           && inventTransPosting.ETGVertical == _ver
           && inventTransPosting.ETGSubVertical == _subVer
           && inventTransPosting.IsPosted == NoYes::Yes;

        if (inventTransPosting.RecId)
        {
            salesTable = SalesTable::find(inventTransOrigin.ReferenceId);
            custTable = salesTable ? CustTable::find(salesTable.CustAccount) : null;

            if (custTable && custTable.CustGroup == '40')
            {
                select firstOnly custInvoiceTrans
                where custInvoiceTrans.InvoiceId == inventTrans.InvoiceId
                   && custInvoiceTrans.InventTransId == inventTransOrigin.InventTransId
                   && CustInvoiceTrans.InvoiceDate == inventTrans.DateFinancial;

                if (!summedTrans.in(custInvoiceTrans.RecId))
                {
                    salesValue += custInvoiceTrans.LineAmountMST;
                    summedTrans.add(custInvoiceTrans.RecId);
                }

            }
        }
    }

    return salesValue;
}

public static Map getDimensionMap(DimensionDefault dimDefault, ETGACFParameters aCFParameters)
{
    Map dimMap = new Map(Types::String, Types::String);

    dimMap.insert("ItemId", ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(dimDefault, aCFParameters.ItemId));
    dimMap.insert("MainCommodity", ETGFinancialDimensionHelper::getDimensionDisplayValue(dimDefault, aCFParameters.MainCommodity));
    dimMap.insert("SubCommodity", ETGFinancialDimensionHelper::getDimensionDisplayValue(dimDefault, aCFParameters.SubCommodity));
    dimMap.insert("Vertical", ETGFinancialDimensionHelper::getDimensionDisplayValue(dimDefault, aCFParameters.Vertical));
    dimMap.insert("SubVertical", ETGFinancialDimensionHelper::getDimensionDisplayValue(dimDefault, aCFParameters.SubVertical));


    return dimMap;
}

public AmountMST getExchangeRate()
{
    ExchangeRate     exchangeRate;
    ExchangeRateType ExchangeRateType;
    ExchangeRateCurrencyPair exchangeRateCurrencyPair;
    real             exchRate;

    CurrencyCode fromCurrency  = "AED";
    CurrencyCode toCurrency    = "USD";
    TransDate    transDate     = today();

    select firstonly exchangeRateCurrencyPair
    where
    exchangeRateCurrencyPair.ExchangeRateType
    == Ledger::find(Ledger::current()).DefaultExchangeRateType
    &&  exchangeRateCurrencyPair.FromCurrencyCode == fromCurrency
    &&  exchangeRateCurrencyPair.ToCurrencyCode   == toCurrency;

    exchRate = exchangeRate::findByDate(exchangeRateCurrencyPair.RecId,
        transDate).ExchangeRate;

    return (exchRate/100);
}
